export const Dashboard: React.FC = () => {
  const { t } = useLanguage();
  const { user } = useAuth();

  const [loading, setLoading] = useState(true);
  const [activeCount, setActiveCount] = useState(0);
  const [totalSaved, setTotalSaved] = useState(0);

  // Mixed activity list
  const [activityFeed, setActivityFeed] = useState<any[]>([]);
  const [expandedId, setExpandedId] = useState<string | null>(null);

  // Helper to parse cost strings
  const parseCost = (costStr: string | null): number => {
      if (!costStr || costStr === '-') return 0;
      const cleaned = costStr.replace(/[^0-9.-]+/g, "");
      return parseFloat(cleaned) || 0;
  };

  useEffect(() => {
    const fetchDashboardData = async () => {
        if (!user) return;
        setLoading(true);

        // 1. Fetch SOS Tickets
        const { data: tickets, error: ticketsError } = await supabase
            .from('sos_tickets')
            .select('*')
            .eq('user_id', user.id);

        // 2. Fetch Service Orders
        const { data: orders, error: ordersError } = await supabase
            .from('service_orders')
            .select('*')
            .eq('user_id', user.id);

        if (ticketsError) console.error("Error tickets:", ticketsError);
        if (ordersError) console.error("Error orders:", ordersError);

        const safeTickets = tickets || [];
        const safeOrders = orders || [];

        // --- Logic: Stats ---
        // Active Count (Both types)
        const activeTickets = safeTickets.filter(t => t.status === 'pending' || t.status === 'in_progress').length;
        const activeOrders = safeOrders.filter(o => o.status === 'pending' || o.status === 'in_progress').length;
        setActiveCount(activeTickets + activeOrders);

        // Savings (Only from SOS for now, maybe orders imply value later)
        let savings = 0;
        safeTickets.forEach(t => {
            const ourCost = parseCost(t.cost);
            const marketCost = parseCost(t.market_cost);
