import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from './supabase';

// Define our custom User type matching the database table structure
export interface User {
  id: number | string;
  email: string;
  role: string;
  business_name?: string;
  subscriptions?: {
    sos_business?: boolean;
    [key: string]: any;
  };
}

interface AuthContextType {
  user: User | null;
  loading: boolean;
  login: (userData: User) => void;
  logout: () => void;
  refreshSession: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  const updateUser = (userData: User) => {
    setUser(userData);
    localStorage.setItem('bunker_user', JSON.stringify(userData));
  };

  const refreshSession = async () => {
    if (!user?.id) return;
    try {
        const { data, error } = await supabase
          .from('app_users')
          .select('*')
          .eq('id', user.id)
          .single();

        if (data && !error) {
           const freshUser: User = {
              id: data.id,
              email: data.email,
              role: data.role,
              business_name: data.business_name,
              subscriptions: data.subscriptions
           };
           updateUser(freshUser);
        }
    } catch (err) {
        console.error("Session refresh failed", err);
    }
  };

  useEffect(() => {
    const initializeAuth = async () => {
      // Check LocalStorage on mount to restore session
      const storedUser = localStorage.getItem('bunker_user');
      if (storedUser) {
        try {
          const parsed = JSON.parse(storedUser);
          setUser(parsed);

          // CRITICAL FIX: Fetch latest data from DB immediately to sync permissions/subscriptions
          // This ensures that if Admin changed rights, the user gets them on reload.
          const { data, error } = await supabase
            .from('app_users')
            .select('*')
            .eq('id', parsed.id)
            .single();

          if (data && !error) {
             const freshUser: User = {
                id: data.id,
                email: data.email,
                role: data.role,
                business_name: data.business_name,
                subscriptions: data.subscriptions
             };
             setUser(freshUser);
             localStorage.setItem('bunker_user', JSON.stringify(freshUser));
          }

        } catch (e) {
          console.error('Failed to parse user session', e);
          localStorage.removeItem('bunker_user');
        }
      }
      setLoading(false);
    };

    initializeAuth();
  }, []);

  const login = (userData: User) => {
    updateUser(userData);
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('bunker_user');
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, refreshSession }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

