import React, { createContext, useContext, useEffect, useState } from 'react';
import { supabase } from './supabase';

// Define our custom User type matching the database table structure
export interface User {
  id: number | string;
  email: string;
  role: string;
  business_name?: string;
  language?: string; // Added language property
  subscriptions?: {
    sos_business?: boolean;
    [key: string]: any;
  };
}

interface AuthContextType {
  user: User | null;
  loading: boolean;
  login: (userData: User) => void;
  logout: () => void;
  refreshSession: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const AuthProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [user, setUser] = useState<User | null>(null);
  const [loading, setLoading] = useState(true);

  const updateUser = (userData: User) => {
    setUser(userData);
    localStorage.setItem('bunker_user', JSON.stringify(userData));
  };

  const refreshSession = async () => {
    if (!user?.id) return;
    try {
        const { data, error } = await supabase
          .from('app_users')
          .select('*')
          .eq('id', user.id)
          .single();

        if (data && !error) {
           const freshUser: User = {
              id: data.id,
              email: data.email,
              role: data.role,
              business_name: data.business_name,
              subscriptions: data.subscriptions,
              language: data.language // Map language from DB
           };
           updateUser(freshUser);
        }
    } catch (err) {
        console.error("Session refresh failed", err);
    }
  };

  useEffect(() => {
    const initializeAuth = async () => {
      // Check LocalStorage on mount to restore session
      const storedUser = localStorage.getItem('bunker_user');
      if (storedUser) {
        try {
          const parsed = JSON.parse(storedUser);
          setUser(parsed);

          // CRITICAL FIX: Fetch latest data from DB immediately to sync permissions/subscriptions
          // This ensures that if Admin changed rights, the user gets them on reload.
          const { data, error } = await supabase
            .from('app_users')
            .select('*')
            .eq('id', parsed.id)
            .single();

          if (data && !error) {
             const freshUser: User = {
                id: data.id,
                email: data.email,
                role: data.role,
                business_name: data.business_name,
                subscriptions: data.subscriptions,
                language: data.language // Map language from DB
             };
             setUser(freshUser);
             localStorage.setItem('bunker_user', JSON.stringify(freshUser));
          }

        } catch (e) {
          console.error('Failed to parse user session', e);
          localStorage.removeItem('bunker_user');
        }
      }
      setLoading(false);
    };

    initializeAuth();
  }, []);

  const login = (userData: User) => {
    updateUser(userData);
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('bunker_user');
  };

  return (
    <AuthContext.Provider value={{ user, loading, login, logout, refreshSession }}>
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { translations } from './translations';
import { Language } from '../types';
import { useAuth } from './AuthContext';
import { supabase } from './supabase';

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: typeof translations['ru'];
  dir: 'ltr' | 'rtl';
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth(); // Access auth context to check for user
  const [language, setLanguageState] = useState<Language>('ru');

  // 1. Initial Load: Try LocalStorage first (visual consistency)
  useEffect(() => {
    const savedLang = localStorage.getItem('language') as Language;
    if (savedLang && ['en', 'he', 'ru'].includes(savedLang)) {
      setLanguageState(savedLang);
    }
  }, []);

  // 2. Sync with User Profile when User loads/changes
  useEffect(() => {
    if (user?.language && ['en', 'he', 'ru'].includes(user.language)) {
       // If user DB language is different from current state, update state
       setLanguageState(user.language as Language);
       localStorage.setItem('language', user.language);
    }
  }, [user]);

  // 3. Document Attributes Sync
  useEffect(() => {
    const dir = language === 'he' ? 'rtl' : 'ltr';
    document.documentElement.dir = dir;
    document.documentElement.lang = language;
  }, [language]);


  // Wrapper for setting language
  const setLanguage = async (lang: Language) => {
    // 1. Update State
    setLanguageState(lang);

    // 2. Update LocalStorage
    localStorage.setItem('language', lang);

    // 3. Update DB if user is logged in
    if (user?.id) {
        try {
            await supabase
                .from('app_users')
                .update({ language: lang })
                .eq('id', user.id);
        } catch (err) {
            console.error("Failed to save language preference", err);
        }
    }
  };

  const value = {
    language,
    setLanguage, // Use the wrapper
    t: translations[language],
    dir: language === 'he' ? 'rtl' : 'ltr' as 'ltr' | 'rtl'
  };

  return (
    <LanguageContext.Provider value={value}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

import React, { createContext, useContext, useState, useEffect } from 'react';
import { translations } from './translations';
import { Language } from '../types';
import { useAuth } from './AuthContext';
import { supabase } from './supabase';

interface LanguageContextType {
  language: Language;
  setLanguage: (lang: Language) => void;
  t: typeof translations['ru'];
  dir: 'ltr' | 'rtl';
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { user } = useAuth();

  // 1. Initialize State Lazy: Read from LocalStorage immediately to avoid flickering 'ru' -> 'en'
  const [language, setLanguageState] = useState<Language>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('language');
      if (saved && ['en', 'he', 'ru'].includes(saved)) {
        return saved as Language;
      }
    }
    return 'ru'; // Fallback only if nothing is saved
  });

  // 2. Sync with User Profile ONLY when user object changes (Login event)
  useEffect(() => {
    // If user exists and has a specific language saved in DB that differs from current
    if (user?.language && ['en', 'he', 'ru'].includes(user.language) && user.language !== language) {
       console.log("Syncing language from User Profile:", user.language);
       setLanguageState(user.language as Language);
       localStorage.setItem('language', user.language);
    }
  }, [user]); // Dependency on 'user' ensures this runs on login/refresh

  // 3. Document Attributes Sync
  useEffect(() => {
    const dir = language === 'he' ? 'rtl' : 'ltr';
    document.documentElement.dir = dir;
    document.documentElement.lang = language;
  }, [language]);


  // Wrapper for setting language
  const setLanguage = async (lang: Language) => {
    // 1. Update State
    setLanguageState(lang);

    // 2. Update LocalStorage
    localStorage.setItem('language', lang);

    // 3. Update DB if user is logged in
    if (user?.id) {
        try {
            await supabase
                .from('app_users')
                .update({ language: lang })
                .eq('id', user.id);
        } catch (err) {
            console.error("Failed to save language preference", err);
        }
    }
  };

  const value = {
    language,
    setLanguage, // Use the wrapper
    t: translations[language],
    dir: language === 'he' ? 'rtl' : 'ltr' as 'ltr' | 'rtl'
  };

  return (
    <LanguageContext.Provider value={value}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

import React, { useState } from 'react';
import { supabase } from '../lib/supabase';
import { Link, useNavigate } from 'react-router-dom';
import { useLanguage } from '../lib/LanguageContext';
import { useAuth } from '../lib/AuthContext';
import { Lock, Mail, ArrowRight, Building2, AlertTriangle } from 'lucide-react';

export const Register: React.FC = () => {
  const { t, language } = useLanguage(); // Get current language
  const { login } = useAuth();
  const navigate = useNavigate();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError(null);

    try {
        // 1. Check if user already exists
        const { data: existingUser } = await supabase
            .from('app_users')
            .select('email')
            .eq('email', email)
            .single();

        if (existingUser) {
            throw new Error('User with this email already exists.');
        }

        // 2. Insert new user into custom table
        // We include the 'language' field here to save the user's current preference
        const { data, error: insertError } = await supabase
            .from('app_users')
            .insert([
                { 
                    email, 
                    password, // Storing as is for "simple table" request. Ideally hash this.
                    role: 'CLIENT',
                    business_name: 'New Client',
                    language: language // Save current language
                }
            ])
            .select()
            .single();

        if (insertError) throw insertError;

        if (data) {
            // 3. Login immediately (save to context/localstorage)
            login({
                id: data.id,
                email: data.email,
                role: data.role,
                business_name: data.business_name,
                language: data.language // Ensure auth context gets the language
            });
            navigate('/');
        }

    } catch (err: any) {
        setError(err.message || 'Registration failed');
    } finally {
        setLoading(false);
    }
  };

  return (
    <div className="min-h-[80vh] flex items-center justify-center px-4">
      <div className="w-full max-w-md bg-bunker-900 border border-white/10 p-8 relative clip-corner overflow-hidden">
        <div className="absolute top-0 right-0 p-3 opacity-20">
            <Building2 size={64} className="text-neon-cyan"/>
        </div>

        <div className="mb-8">
            <h1 className="text-2xl font-tech font-bold text-white mb-2">{t.auth.registerTitle}</h1>
            <div className="h-0.5 w-12 bg-neon-cyan"></div>
        </div>

        {error && (
            <div className="mb-4 p-4 bg-red-500/10 border border-red-500/30 text-red-400 text-xs font-mono flex gap-3 items-start">
                <AlertTriangle className="shrink-0 mt-0.5" size={16} />
                <div>{error}</div>
            </div>
        )}

        <form onSubmit={handleRegister} className="space-y-6">
            <div>
                <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.auth.email}</label>
                <div className="relative">
                    <Mail className="absolute left-3 top-3 text-slate-500" size={16} />
                    <input 
                        type="email" 
                        value={email}
                        onChange={(e) => setEmail(e.target.value)}
                        required
                        className="w-full bg-bunker-950 border border-white/10 pl-10 pr-4 py-3 text-white focus:border-neon-cyan focus:outline-none focus:ring-1 focus:ring-neon-cyan/50 transition-colors"
                        placeholder="business@example.com"
                    />
                </div>
            </div>

            <div>
                <label className="block text-xs font-mono text-slate-400 mb-2 uppercase">{t.auth.password}</label>
                <div className="relative">
                    <Lock className="absolute left-3 top-3 text-slate-500" size={16} />
                    <input 
                        type="password" 
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        required
                        className="w-full bg-bunker-950 border border-white/10 pl-10 pr-4 py-3 text-white focus:border-neon-cyan focus:outline-none focus:ring-1 focus:ring-neon-cyan/50 transition-colors"
                        placeholder="••••••••"
                    />
                </div>
            </div>

            <button 
                type="submit" 
                disabled={loading}
                className="w-full bg-neon-cyan text-bunker-950 font-bold font-mono py-3 uppercase tracking-widest hover:bg-white transition-all disabled:opacity-50 flex items-center justify-center gap-2"
            >
                {loading ? 'Processing...' : t.auth.submitRegister}
                {!loading && <ArrowRight size={16} />}
            </button>
        </form>

        <div className="mt-6 text-center border-t border-white/5 pt-4">
            <span className="text-xs text-slate-500">{t.auth.hasAccount} </span>
            <Link to="/login" className="text-xs text-neon-cyan hover:underline font-mono uppercase">{t.auth.loginLink}</Link>
        </div>
      </div>
    </div>
  );
};

